<template>
  <ul class="menu-bar-ex navbar-nav">
    <li v-for="(item,index) in menuItems" class="menu-item nav-item" :key="index" :class="{active:item.link===$route.path}">
      <router-link :to="item.link" data-toggle="collapse" data-target="#navbarNav" class="nav-link">
        <div class="row no-p-m">
          <!-- Menu icon -->
          <div class="col-1 no-padding align-self-center">
            <em class="fa menu-icon" :class="item.icon"></em>
          </div>
          <!-- Menu title -->
          <div class="col-11 no-p-m align-self-center">
            <Strong class="menu-title">{{item.title}}</Strong>
          </div>
        </div>
      </router-link>
    </li>
  </ul>
</template>

<script>
export default {
  name: 'MenuItemsEx',
  props: ['menuItems']
}
</script>

<style scoped>

  .no-padding {
    padding: 0;
  }

  .no-p-m {
    padding: 0;
    margin: 0
  }

  .menu-bar-ex {
    list-style: none;
    padding: 0;
    margin: 0;
    width: 100%;
    height: 100%;

  }

  .menu-bar-ex .menu-item {

    border-bottom: 0.01rem var(--menu-items-ex-separator-color) solid;
    font-size: var(--menu-items-ex-font-size);
    cursor: pointer;

  }

  .menu-bar-ex .menu-item:last-child {
    border-bottom: 0;
  }

  .menu-bar-ex .menu-item em.menu-icon {
    text-align: center;
    width: inherit;
    height: inherit;
  }

  .menu-bar-ex .menu-item strong.menu-title {
    text-align: left;
    font-size: var(--menu-items-ex-title-font-size);
  }

  .menu-bar-ex .menu-item a {
    display: block;
    padding: 0.85rem 0;
    text-decoration: none !important;

    transition: color var(--menu-items-transition) linear;
    -o-transition: color var(--menu-items-transition) linear;
    -moz-transition: color var(--menu-items-transition) linear;
    -webkit-transition: color var(--menu-items-transition) linear;
  }

</style>



