import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

const state = {
  storeObj: {}
}

const mutations = {
  SET_STORE (state, storeObj) {
    state.storeObj = storeObj
  },
  RESET_CONFIG (state) {
    state.storeObj = {}
  },
  SET_ITEM (state, {key, value}) {
    Vue.set(state.storeObj, key, value)
  }
}

const actions = {

  setItem: function ({commit}, item) {
    commit('SET_ITEM', {key: item.key, value: item.value})
  }

}

// getters are functions
const getters = {
  getItem: (state) => (item) => { return state.storeObj[item] }

}

export default new Vuex.Store({
  state,
  getters,
  actions,
  mutations
})



