<template>
  <!-- Modal -->
  <transition name="modal">
    <!-- Modal dark background-->
    <div class="modal-backdrop" v-if="modalShow" @click.self="closeModal()">

      <!-- Buttons -->
      <a class="carousel-control-close" href="#modalCarousel" role="button" @click="closeModal()" >
        <span class="carousel-control-close-icon" aria-hidden="true"></span>
        <span class="sr-only">Close</span>
      </a>

      <a class="carousel-control-prev" href="#modalCarousel" role="button" data-slide="prev">
        <span class="carousel-control-prev-icon" aria-hidden="true"></span>
        <span class="sr-only">Previous</span>
      </a>
      <a class="carousel-control-next" href="#modalCarousel" role="button" data-slide="next">
        <span class="carousel-control-next-icon" aria-hidden="true"></span>
        <span class="sr-only">Next</span>
      </a>

      <!-- Modal dialog-->
      <div class="modal-dialog modal-dialog-centered modal-lg" role="document">

        <div class="modal-content">

          <!-- Caoursel -->
          <div id="modalCarousel" class="carousel slide" data-ride="carousel">

            <!-- Indicators -->
            <ol class="carousel-indicators">
              <li v-for="(item,index) in modalContent" data-target="#modalCarousel"
                  :data-slide-to="index"
                  :class="{'active':index===0}"
                  :key="index">
              </li>
            </ol>

            <!-- Images -->
            <div class="carousel-inner">
              <div v-for="(item,index) in modalContent"
                   :class="{'active':index===0}"
                   :key="index"
                   class="carousel-item ">
                <!-- Image -->
                <img class="d-block carousel-img rounded shadow" :src="item.url"/>
                <!-- Caption -->
                <div v-if="item.title" class="carousel-caption">
                  <h6 class="carousel-title p-3 rounded">{{item.title}}</h6>
                </div>
                </div>

            </div>

          </div>

        </div>
      </div>
    </div>
  </transition>

</template>

<script>
export default {
  name: 'GalleryModal',
  props: ['modalShow', 'modalTitle', 'modalContent'],
  methods: {
    closeModal: function () {
      this.$emit('closemodal')
    }
  },
  mounted () {
    document.addEventListener('keydown', (e) => {
      if (this.modalShow === true && e.keyCode === 27) {
        this.closeModal()
      }
    })
  },
  updated () {
    /* this.$refs.modalBody.scrollTo(0, 0) */
  }
}
</script>

<style scoped>
  .modal-backdrop {
    position: fixed;
    top: 0;
    bottom: 0;
    left: 0;
    right: 0;
    background-color: var(--modal-dark-color);
    display: flex;
    justify-content: center;
    align-items: center;

    transition: all var(--modal-transition) ease;
    -o-transition: all var(--modal-transition) ease;
    -moz-transition: all var(--modal-transition) ease;
    -webkit-transition: all var(--modal-transition) ease;
  }

  .modal-content {
    transition: all 0.3s ease;
    max-width: 100vw;
    background-color: transparent;
    border-radius: 0;
    box-shadow: none;
    border:0;
  }

  .carousel-caption {
    position: absolute;
    right: 15%;
    bottom: 1.25rem !important;
    left: 15%;
    z-index: 10;
    padding-top: 1.25rem !important;
    padding-bottom: 1.25rem !important;
    color: #fff;
    text-align: center;
  }

  .carousel-item{
    margin-top:8rem;
    padding-bottom: 8rem;
    padding-left:4rem;
    padding-right:4rem;
  }

  .carousel-img{
    background: url('/static/media/loading.gif') no-repeat center;
    width: inherit;
    height:inherit;
    min-width:96px;
    min-height:96px;

  }

  .carousel-title{
    background-color:#000a;
  }

  .modal-enter {
    opacity: 0;

  }

  .modal-leave-active {
    opacity: 0;
  }

  .modal-enter .modal-content,
  .modal-leave-active .modal-content {

    transform: scale(1.1);
    -o-transform: scale(1.1);
    -moz-transform:scale(1.1);
    -ms-transform: scale(1.1);
    -webkit-transform: scale(1.1);

  }

  .carousel-control-close,
  .carousel-control-prev,
  .carousel-control-next {
    position: absolute;
    top: unset !important;
    bottom: unset !important;
    display: -ms-flexbox;
    display: flex;
    -ms-flex-align: center;
    align-items: center;
    -ms-flex-pack: center;
    justify-content: center;
    width: 3rem;
    height:3rem;
    color: #fff;
    text-align: center;
    opacity: 0.5;
    background-color: black;
    padding:1rem;
    margin:1rem;
    border-radius: 50%;
    z-index: 8000;
  }

  .carousel-control-close:hover,
  .carousel-control-prev:hover,
  .carousel-control-next:hover{
    background-color: #111;
  }

  .carousel-control-close{
    top:0 !important;
    right:0 !important;
  }

  .carousel-control-close-icon{
    display: inline-block;
    width: 20px;
    height: 20px;
    background: transparent no-repeat center center;
    background-size: 100% 100%;
  }

  .carousel-control-close-icon {
    background-image: url("data:image/svg+xml;charset=utf8,%3Csvg xmlns='http://www.w3.org/2000/svg' fill='%23fff' viewBox='0 0 8 8'%3E%3Cpath d='M 6.4963889,3.12e-5 3.9944854,2.501486 1.4994854,0.0069335 0,1.5061499 2.4991421,4.0048439 0.00276135,6.5007768 1.5022469,7.9999934 3.9986276,5.5040603 l 0.00139,-0.00139 2.4950003,2.4945529 0.00139,-0.00139 0.00412,0.00411 L 8,6.5007325 5.5008576,4.0020385 7.9972387,1.5061054 l -0.00414,-0.00414 0.00275,-0.00275 L 6.4963654,0 Z'/%3E%3C/svg%3E");
  }

</style>



