<template>
  <main-panel :tab-items="tabItems">
    <div class="tab-content">
      <!-- About Tab -->
      <div class="tab-pane active in" id="about">
        <div class="container w-100 pt-3">
          <!-- About Section -->
          <h5 class="pr-3"><em class="fa fa-user pr-3"></em>About Me</h5>
          <div class="row">
            <!-- About paragraph -->
            <div class="col-sm-12 col-md-8 pr-md-4">
              <p class="about-par">
                {{aboutIntro}}
              </p>
            </div>
            <!-- About bullets paragraph -->
            <div class="col-sm-12 col-md-4 align-self-center about-divider">
              <h6 v-for="(item,index) in aboutItems" :key="index">
                <em class="pr-3" :class="item.icon"></em>{{item.title}}
              </h6>
            </div>
          </div>

          <!-- Buttons -->
          <div class="row">
            <div class="btn-group-lg p-3">
              <button class="btn btn-outline-primary" disabled>Download CV</button>
              <a class="btn btn-outline-dark" :href="'mailto:'+contactEmail">Contact Me</a>
            </div>
          </div>

          <hr class="mb-4">

          <!-- Research Interests -->
          <h5><em class="fa fa-magic pr-3"></em>Research Interests</h5>
          <div class="row">
            <div class="col">
              <p class="about-par">{{researchArea}}</p>
            </div>
          </div>

        </div>
      </div>

      <!-- Latest Events Tab -->
      <div class="tab-pane" id="events">
        <div class="container pt-3">
          <!-- Latest Events Section -->
          <h5 class="pr-3"><em class="fa fa-calendar pr-3"></em>Latest Events</h5>
          <div class="row">
            <div class="col-12">
              <events-item v-if="events" :ev-items="events" class="p-3"></events-item>
              <small v-else class="text-muted pl-3">Content not available</small>
            </div>
          </div>
        </div>
      </div>

    </div>
  </main-panel>
</template>

<script>
import BubbleTab from '@/components/elements/BubbleTab'
import MainPanel from '@/components/layout/MainPanel'
import SiteConfig from '@/site-conf'
import {StoreMx} from '@/mixins/StoreMx'
import EventsItem from '@/components/items/EventsItem'

export default {
  name: 'AboutView',
  mixins: [StoreMx],
  components: {EventsItem, MainPanel, BubbleTab},
  created: function () {
    let vm = this
    vm.events = vm.storeGetItem('EVENTS')
  },
  data: function () {
    return {
      contactEmail: SiteConfig.about.email,
      tabItems: SiteConfig.tabs.aboutView,
      aboutIntro: SiteConfig.about.intro,
      aboutItems: SiteConfig.about.items,
      researchArea: SiteConfig.about.researchArea,
      events: null

    }
  }
}
</script>

<style scoped>

  .about-par {
    font-size: 1.1rem;
    text-align: justify
  }

  @media (min-width: 576px) {
    .about-divider {
      border-left: 0;
    }
  }

  @media (min-width: 768px) {
    .about-divider {
      border-left: 1px #d8dbe2 solid;
    }
  }

</style>



