<template>
  <div class="card card-cover">
    <!-- Cover img -->
    <div class="cover-img" :style="{'background-image':'url('+sideBar.coverImg+')'}"></div>

    <!-- Profile img -->
    <div class="row justify-content-center">
      <img class="profile-img rounded-circle shadow" :src="sideBar.profileImg">
    </div>

    <div class="card-body p-0">

      <!-- Information -->
      <h4 class="card-title text-center mt-2">{{sideBar.displayName}}</h4>
      <hr class="mb-3 mt-2"/>
      <h6 class="text-center">{{sideBar.headerName}}</h6>

      <!-- Menu items -->
      <div class="row" style="margin-right:-1.0rem !important;">
        <menu-items :menu-items="menuItems"></menu-items>
      </div>

      <!-- Footer links -->
      <div class="row justify-content-center mt-2">
        <footer-links :foot-links="footLinks"></footer-links>
      </div>

      <!-- Copyright subscript -->
      <div class="row justify-content-center">
        <small class="text-muted mt-2">{{sideBar.copyright}}</small>
      </div>

    </div>
  </div>
</template>

<script>
import MenuItems from '@/components/elements/MenuItems'
import FooterLinks from '@/components/elements/FooterLinks'
import SiteConfig from '@/site-conf'

export default {
  name: 'SideBar',
  components: {FooterLinks, MenuItems},
  data: function () {
    return {
      sideBar: SiteConfig.sideBar,
      menuItems: SiteConfig.menuItems,
      footLinks: SiteConfig.footerLinks
    }
  }
}
</script>

<style scoped>

  .card-cover {
    padding: 4.85rem 1rem 1rem 1rem !important;
  /*  box-shadow: 10px 10px 15px rgba(0, 0, 0, 0.05);*/
    box-shadow:  0 2px 45px 5px rgba(0, 0, 0, 0.09);
    border-radius: 0.5rem !important;

    height:40.71rem;
    z-index: 5500;
    transition: none;
  }

  .profile-img {
    height: 7.2rem;
    width: 7.2rem;
    z-index: 1000;
    padding: 0.15rem;
    background-color: white;
  }

  .cover-img {
    position: absolute;
    overflow: hidden;
    left: 0;
    top: 0;
    width: 100%;
    height: 11.25rem;
    z-index: 0;

    background-position: center center;
    background-size: cover;
    border-radius: 0.5rem 0.5rem 0 0;
    -moz-border-radius: 0.5rem 0.5rem 0 0;
    -webkit-border-radius: 0.5rem 0.5rem 0 0;
    -khtml-border-radius: 0.5rem 0.5rem 0 0;
  }

  .cover-img:before,
  .cover-img:after {
    content: '';
    position: absolute;
    left: -20%;
    bottom: -78%;
    width: 120%;
    height: 100%;
    background: #fff;
    transform: rotate(12deg);
    -webkit-transform: rotate(12deg);
    -moz-transform: rotate(12deg);
    -o-transform: rotate(12deg);
    z-index: 1;
  }

</style>



