<template>
  <table class="table table-bordered table-striped table-hover w-100">
    <tbody v-show="tableRows">
    <tr v-for="(row,index) in tableRows" :key="index">
      <td class="text-center" v-if="row.key">{{row.key}}</td>
      <td v-else class="text-muted text-center">Not defined</td>
      <td class="text-center" v-if="row.value">{{row.value}}</td>
      <td v-else class="text-muted text-center">Not defined</td>
    </tr>
    </tbody>
  </table>
</template>

<script>
export default {
  name: 'StripedTable',
  props: ['tableRows']
}
</script>



