<template>
  <main-panel :tab-items="tabItems">
    <div class="tab-content">
      <!-- Projects Tab -->
      <div class="tab-pane active in" id="prj">
        <div class="container w-100 pt-2">
          <project-item
            v-for="(item,index) in projects"
            :prj-item="item"
            :key="index"
            :prj-index="index"
            :is-last="index===projects.length-1"
            @absClick="showAbstract"
            @galClick="showGallery">
          </project-item>
          <small v-if="!projects" class="text-muted" >Content not available</small>
        </div>
      </div>

      <!-- Presentations Tab -->
      <div class="tab-pane" id="pre" >
        <div class="container w-100 pt-2">
          <presentation-item
            v-for="(item,index) in presentations"
            :pre-item="item"
            :key="index"
            :pre-index="index"
            :is-last="index===presentations.length-1"
            @absClick="showAbstractPre"
            @galClick="showGalleryPre">
          </presentation-item>
          <small v-if="!presentations" class="text-muted" >Content not available</small>
        </div>
      </div>
    </div>
  </main-panel>
</template>

<script>
import ProjectItem from '@/components/items/ProjectItem'
import PresentationItem from '@/components/items/PresentationItem'
import MainPanel from '@/components/layout/MainPanel'
import SiteConfig from '@/site-conf'
import {StoreMx} from '@/mixins/StoreMx'

export default {
  name: 'ProjectsView',
  mixins: [StoreMx],
  components: {MainPanel, PresentationItem, ProjectItem},

  created: function () {
    let vm = this
    this.projects = vm.storeGetItem('PROJECTS')
    this.presentations = vm.storeGetItem('PRESENTATIONS')
  },
  data: function () {
    return {
      tabItems: SiteConfig.tabs.projectView,
      projects: null,
      presentations: null
    }
  },
  methods:
    {
      showAbstract: function (index) {
        this.$emit('show-modal',
          this.projects[index].title,
          this.projects[index].extra.abstract,
          false)
      },
      showGallery: function (index) {
        this.$emit('show-modal',
          this.projects[index].title,
          this.projects[index].extra.gallery, true)
      },
      showAbstractPre: function (index) {
        this.$emit('show-modal',
          this.presentations[index].title,
          this.presentations[index].extra.abstract,
          false)
      },
      showGalleryPre: function (index) {
        this.$emit('show-modal',
          this.presentations[index].title,
          this.presentations[index].extra.gallery, true)
      }
    }

}
</script>

<style scoped>

</style>



