<template>
  <ul class="bub-group nav">
    <li v-for="(item,index) in bubItems" :key="index">
      <a :href="item.href"
         class="bub-btn"
         :class="{'active':index===0}"
         data-toggle="list"
         @click="$emit('bubClick')">
        <em class="fa" :class="item.icon"></em>
        <strong class="title">{{item.title}}</strong>
      </a>
    </li>
  </ul>
</template>

<script>
export default {
  name: 'BubbleTab',
  props: ['bubItems']
}
</script>

<style scoped>

  .bub-group .bub-btn {
    display: inline-block;
    position: relative;
    cursor: pointer;
    margin:0.25rem;
    text-decoration: none;
    font-size: var(--bubble-font-size);
  }

  .bub-group .bub-btn:before {
    display: inline-block;
    position: absolute;
    content: '';
    width: var(--bubble-radius);
    height: var(--bubble-radius);
    background-color: var(--bubble-dark-color);
    color: var(--bubble-light-color);
    border-radius: 5rem !important;

    transition: var(--bubble-transition) ease-in-out;
    -o-transition: var(--bubble-transition) ease-in-out;
    -moz-transition: var(--bubble-transition) ease-in-out;
    -webkit-transition: var(--bubble-transition) ease-in-out;
  }

  .bub-group .bub-btn em {
    display: inline-block;
    position: relative;
    text-align: center;
    width: var(--bubble-radius);
    height: var(--bubble-radius);
    line-height:var(--bubble-radius);
    color: var(--bubble-light-color);
    font-size: inherit !important;

  }

  .bub-group .bub-btn .title {
    display: inline-block;
    position: relative;
    font-size: inherit !important;
    padding-right: 1rem;
    height:  var(--bubble-radius);
    line-height:  var(--bubble-radius);
    color: var(--bubble-dark-color);

    transition: var(--bubble-transition) ease-in-out;
    -o-transition: var(--bubble-transition) ease-in-out;
    -moz-transition: var(--bubble-transition) ease-in-out;
    -webkit-transition: var(--bubble-transition) ease-in-out;
  }

  .bub-group .bub-btn:hover .title {
    color: var(--bubble-light-color);

  }

  .bub-group .bub-btn:hover:before {
    width: 100%;
    background-color: var(--bubble-darker-color);
  }

  .bub-group .bub-btn.active .title {
    color: var(--bubble-light-color);

  }

  .bub-group .bub-btn.active:before {
    width: 100%;
  }

  .bub-group .bub-btn.active:hover:before {
    width: 100%;
    background-color: var(--bubble-darker-color);

  }
</style>



