<template>
  <div>
    <div class="row">
      <!--Info section -->
      <div class="col-10">

        <!-- Introductory line -->
        <h5 v-if="pubItem.title">{{pubItem.title}}</h5>
        <h5 v-else class="text-muted font-italic">Not defined</h5>

        <!-- Details -->
        <div class="pl-2 pt-2">
          <key-value :key-text="pubItem.type" :value-text="pubItem.location"></key-value>
          <key-value key-text="Authors" :value-text="pubItem.authors"></key-value>
          <key-value key-text="DOI" :value-text="pubItem.doi"></key-value>
          <key-value key-text="Publication date" :value-text="pubItem.date"></key-value>
        </div>

        <!-- Buttons -->
        <div class="btn-group-sm pl-1 pt-1" v-if="pubItem.extra">
          <button v-if="pubItem.extra.abstract" class="btn btn-outline-dark"
                  @click="$emit('absClick',pubIndex)">
            <em class="fa fa-stream btn-icon"></em>Abstract
          </button>
          <a class="btn btn-outline-dark"
             v-if="pubItem.extra.pubUrl"
             :href="pubItem.extra.pubUrl"
             target="_blank">
            <em class="fa fa-globe btn-icon"></em>Publication page
          </a>
          <a class="btn btn-outline-dark"
             v-if="pubItem.extra.pageUrl"
             :href="pubItem.extra.pageUrl"
             target="_blank">
            <em class="fa fa-globe btn-icon"></em>Project page
          </a>
          <a class="btn btn-outline-dark"
                  v-if="pubItem.extra.bibtexUrl"
                  :href="pubItem.extra.bibtexUrl"
                  target="_blank">
            <em class="fa fa-paperclip btn-icon"></em>Bibtex
          </a>
        </div>

      </div>

      <!-- Thumbnail -->
      <div class="col-2 align-self-center">
        <div class="row justify-content-center" v-show="pubItem.thumbnail">
          <small class="text-muted">{{pubItem.thumbTitle}}</small>
          <img class="list-thumb" :src="pubItem.thumbnail"/>
        </div>
      </div>
    </div>

    <!-- Separator -->
    <hr v-show="!isLast" class="mt-4 mb-4">
  </div>
</template>

<script>
import KeyValue from '@/components/elements/KeyValue'
export default {
  name: 'PublicationItem',
  components: {KeyValue},
  props: ['pubItem', 'pubIndex', 'isLast']
}
</script>

<style scoped>

  .list-thumb {
    width:var(--thumb-size-mob);
    height:var(--thumb-size-mob);
  }

  @media (min-width: 544px) {
    .list-thumb {
      width: var(--thumb-size);
      height: var(--thumb-size);
    }
  }

  em.btn-icon {
    margin-right: 0.25rem !important;
    line-height: 1rem;
  }
</style>



