export const StoreMx = {
  data () {
    return {
    }
  },
  created: function () {

  },
  methods: {
    storeFetchItem: async function (url, itemName) {
      try {
        let promise = await fetch(url)
        let jsonObj = await promise.json()
        this.$store.dispatch('setItem', {key: itemName, value: jsonObj})
      } catch (e) {
        console.error('Error occurred while loading ' + url)
        console.error(e.message)
        this.$store.dispatch('setItem', {key: itemName, value: undefined})
      }
    },
    storeGetItem: function (itemName) {
      return this.$store.getters['getItem'](itemName)
    },
    storeSetItem: function (itemName, itemValue) {
      this.$store.dispatch('setItem', {key: itemName, value: itemValue})
    }
  }
}



