<template>

  <div>
    <div class="row">
      <!--Info section -->
      <div class="col-10">

        <!-- Introductory lines -->
        <h5 v-if="expItem.role">{{expItem.role}}</h5>
        <h5 v-else>Not defined</h5>
        <h5 v-if="expItem.title">{{expItem.title}}</h5>
        <h6 v-if="expItem.location">{{expItem.location}}</h6>
        <h6 v-if="expItem.date" class="font-italic">{{expItem.date}}</h6>

        <!-- Details -->
        <div class="pl-2 pt-2">
          <key-value
            key-text="Description"
            :value-text="expItem.desc"
            head-class="text-justify">
          </key-value>
        </div>

      </div>

      <!-- Thumbnail -->
      <div class="col-2 align-self-center">
        <div class="row justify-content-center" v-if="expItem.thumbnail">
          <img class="list-thumb" :src="expItem.thumbnail"/>
        </div>
      </div>
    </div>

    <!-- Separator -->
    <hr v-show="!isLast" class="mt-4 mb-4">
  </div>
</template>

<script>
import KeyValue from '@/components/elements/KeyValue'
export default {
  name: 'ExperienceItem',
  components: {KeyValue},
  props: ['expItem', 'isLast']
}
</script>

<style scoped>
  .list-thumb {
    width:var(--thumb-size-mob);
    height:var(--thumb-size-mob);
  }

  @media (min-width: 544px) {
    .list-thumb {
      width: var(--thumb-size);
      height: var(--thumb-size);
    }
  }
</style>



