<template>
  <ul class="menu-bar">
    <li v-for="(item,index) in menuItems" class="menu-item" :key="index" :class="{active:item.link===$route.path}">
      <router-link :to="item.link" data-toggle="pills"  data-target="#">
        <div class="row no-p-m">
          <!-- Menu icon -->
          <div class="col-2 offset-1 no-padding align-self-center">
            <em class="fa menu-icon" :class="item.icon"></em>
          </div>
          <!-- Menu title -->
          <div class="col-9 no-p-m align-self-center">
            <Strong class="menu-title">{{item.title}}</Strong>
          </div>
        </div>
      </router-link>
    </li>
  </ul>
</template>

<script>

export default {
  name: 'MenuItems',
  props: ['menuItems']
}
</script>

<style scoped>

  .no-padding{
    padding:0;
  }

  .no-p-m{
    padding:0;
    margin:0
  }
  .menu-bar {
    list-style: none;
    padding: 0;
    margin: 0;
    width: 100%;
    height: 100%;

  }

  .menu-bar .menu-item {

    border-bottom: 0.01rem var(--menu-items-separator-color) solid;
    border-right: 0.25rem var(--menu-items-border-color) solid;
    font-size: var(--menu-items-font-size);
    cursor: pointer;

    transition: border-right var(--menu-items-transition) linear;
    -o-transition: border-right var(--menu-items-transition) linear;
    -moz-transition: border-right var(--menu-items-transition) linear;
    -webkit-transition: border-right var(--menu-items-transition) linear;
  }

  .menu-bar .menu-item:last-child {
    border-bottom: 0;
  }

  .menu-bar .menu-item:hover {
    border-right: 0.25rem  var(--menu-items-border-color-hover) solid;
  }

  .menu-bar .menu-item:focus {
    border-right: 0.25rem  var(--menu-items-border-color-hover) solid;
  }

  .menu-bar .menu-item.active {
    border-right: 0.25rem  var(--menu-items-border-color-hover) solid;
  }

  .menu-bar .menu-item em.menu-icon {
    text-align: center;
    width: inherit;
    height: inherit;
    font-size: inherit;
  }

  .menu-bar .menu-item strong.menu-title {
    text-align: left;
    font-size: var(--menu-items-title-font-size);
  }

  .menu-bar .menu-item a {
    display: block;
    padding: 0.85rem 0;
    text-decoration: none !important;
    color: var(--menu-items-text-color);

    transition: color var(--menu-items-transition) linear;
    -o-transition: color var(--menu-items-transition) linear;
    -moz-transition: color var(--menu-items-transition) linear;
    -webkit-transition: color var(--menu-items-transition) linear;
  }

  .menu-bar .menu-item:hover a {
    text-decoration: none !important;
    color: var(--menu-items-text-color-hover);

  }

  .menu-bar .menu-item.active a {
    text-decoration: none !important;
    color: var(--menu-items-text-color-hover);

  }

</style>



