<template>
  <div>
    <div class="row">
      <!--Info section -->
      <div class="col-10">

        <!-- Introductory lines -->
        <h5 v-if="eduItem.title">{{eduItem.title}}</h5>
        <h5 v-else class="text-muted font-italic">Not defined</h5>
        <h6 v-if="eduItem.location">{{eduItem.location}}</h6>
        <h6 v-if="eduItem.date" class="font-italic">{{eduItem.date}}</h6>

        <!-- Details -->
        <div class="pl-2 pt-2">
          <key-value v-for="(value,key,index) in eduItem.items"
                     :key-text="key" key-class="text-capitalize"
                     :value-text="value"
                     :key="index">
          </key-value>
        </div>

      </div>

      <!-- Thumbnail -->
      <div class="col-2 align-self-center">
        <div class="row justify-content-center" v-if="eduItem.thumbnail">
          <img class="list-thumb" :src="eduItem.thumbnail"/>
        </div>
      </div>
    </div>

    <!-- Separator -->
    <hr v-show="!isLast" class="mt-4 mb-4">
  </div>
</template>

<script>
import KeyValue from '@/components/elements/KeyValue'
export default {
  name: 'EducationItem',
  components: {KeyValue},
  props: ['eduItem', 'isLast']
}
</script>

<style scoped>

  .list-thumb {
    width:var(--thumb-size-mob);
    height:var(--thumb-size-mob);
  }

  @media (min-width: 544px) {
    .list-thumb {
      width: var(--thumb-size);
      height: var(--thumb-size);
    }
  }
</style>



