<template>
  <h6 v-if="keyText" :class="headClass">
    <strong :class="keyClass">{{keyText}}: </strong>
    <span v-if="valueText" :class="valueClass">
      <span v-if="typeof valueText=='string'">
       {{valueText}}
      </span>
      <a class="kv-link" v-else :href="valueText.link" target="_blank">{{valueText.title}}</a>
    </span>
    <span v-else class="text-muted font-italic">Not defined</span>
  </h6>
</template>

<script>
export default {
  name: 'KeyValue',
  props: ['headClass', 'keyClass', 'valueClass', 'keyText', 'valueText']
}
</script>

<style scoped>
  .kv-link{
    color: #002762;
    text-decoration: underline;
  }
  .kv-link:hover{
    color: #0056b3;
  }
</style>



