<template>
  <div class="footer-link">
    <a v-for="(item,index) in footLinks" target="_blank" class="rounded-circle shadow-sm"
       :title="item.title"
       :href="item.url"
       :key="index">
      <em class="fab" :class="item.icon"></em>
    </a>
  </div>
</template>

<script>

export default {
  name: 'FooterLinks',
  props: ['footLinks']
}
</script>

<style scoped>

  .footer-link a {

    display: inline-block;
    margin: 0.25rem;
    text-decoration: none;
    font-size: var(--footer-font-size);
  }

  .footer-link a:before {

    display: inline-block;
    position: absolute;
    width: var(--footer-radius);
    height: var(--footer-radius);
    content: '';
    background-color: var(--footer-back-color) !important;
    border: 0.12rem solid var(--footer-dark-color);
    border-radius: 50% !important;

    transition: background-color var(--footer-transition) linear;
    -o-transition: background-color var(--footer-transition) linear;
    -moz-transition: background-color var(--footer-transition) linear;
    -webkit-transition: background-color var(--footer-transition) linear;
  }

  .footer-link a:hover:before {

    background-color: var(--footer-dark-color) !important;
  }

  .footer-link a > em {

    display: inline-block;
    position: relative;
    width: var(--footer-radius);
    height: var(--footer-radius);
    font-size: inherit;
    line-height: var(--footer-radius) !important;
    text-align: center;
    vertical-align: middle;
    color: var(--footer-dark-color);

    transition: background-color var(--footer-transition) linear;
    -o-transition: background-color var(--footer-transition) linear;
    -moz-transition: background-color var(--footer-transition) linear;
    -webkit-transition: background-color var(--footer-transition) linear;

  }

  .footer-link a > em:hover {

    color: var(--footer-light-color) !important;

  }

</style>



