<template>
  <div class="cssload-container" :style="{'background-image':'url('+loadingImg+')'}"></div>
</template>

<script>
export default {
  name: 'LoadingDiv',
  props: ['loadingImg']
}
</script>

<style scoped>

  .cssload-container {
    display: inline-block;
    position: relative;
    text-align: center;
    width: var(--loading-img-size);
    height: var(--loading-img-size);
    background-position: center;
    background-size: var(--loading-img-size);
    border-radius: 50%;
    box-shadow: 0 0 15px 0 rgba(0, 0, 0, 0.8);
    padding: 0;
    margin: 0;
  }

  .cssload-container:before {
    display: inline-block;
    position: absolute;
    content: '';
    top: 0;
    left: 0;
    width: var(--loading-img-size);
    height: var(--loading-img-size);
    z-index: 10000;

    border-radius: 50%;
    border: 0.2rem solid rgba(0, 0, 100, 0.8);
    border-right-color: transparent;
    border-top-color: transparent;

    animation: cssload-spin 1s infinite linear;
    -o-animation: cssload-spin 1s infinite linear;
    -ms-animation: cssload-spin 1s infinite linear;
    -webkit-animation: cssload-spin 1s infinite linear;
    -moz-animation: cssload-spin 1s infinite linear;

  }

  .cssload-container:after {
    display: inline-block;
    position: absolute;
    content: '';
    top: 0;
    left: 0;
    width: var(--loading-img-size);
    height: var(--loading-img-size);
    z-index: 10000;

    border-radius: 50%;
    border: 0.2rem solid transparent;
    border-right-color: rgba(0, 100, 0, 0.5);
    animation: cssload-spin 1.3s infinite linear;
    -o-animation: cssload-spin 1.3s infinite linear;
    -ms-animation: cssload-spin 1.3s infinite linear;
    -webkit-animation: cssload-spin 1.3s infinite linear;
    -moz-animation: cssload-spin 1.3s infinite linear;

  }

  @keyframes cssload-spin {
    100% {
      transform: rotate(360deg);
    }
  }

  @-o-keyframes cssload-spin {
    100% {
      -o-transform: rotate(360deg);
      transform: rotate(360deg);
    }
  }

  @-ms-keyframes cssload-spin {
    100% {
      -ms-transform: rotate(360deg);
      transform: rotate(360deg);
    }
  }

  @-webkit-keyframes cssload-spin {
    100% {
      -webkit-transform: rotate(360deg);
      transform: rotate(360deg);
    }
  }

  @-moz-keyframes cssload-spin {
    100% {
      -moz-transform: rotate(360deg);
      transform: rotate(360deg);
    }
  }

</style>



