<template>
  <main-panel :tab-items="tabItems">
    <div class="tab-content">
      <!-- Skills Tab -->
      <div class="tab-pane active in" id="skills">
        <div class="container w-100 pt-3 ">
          <!-- Technical Skills -->
          <h5 class="pr-3"><em class="fa fa-laptop-code pr-3"></em>Technical Skills</h5>
          <div class="row m-0">
            <div class="col">
              <striped-table v-if="skills" class="mt-4" :table-rows="skills"></striped-table>
              <small v-else class="text-muted" >Content not available</small>
            </div>
          </div>

          <hr class="mb-4">

          <!-- Language Skills -->
          <h5 class="pr-3"><em class="fa fa-comment pr-3"></em>Language Skills</h5>
          <div class="row p-0 m-0 ">
            <div class="col">
              <striped-table v-if="languages" class="mt-4" :table-rows="languages"></striped-table>
              <small v-else class="text-muted" >Content not available</small>
            </div>
          </div>
        </div>
      </div>

      <!-- Honors Tab -->
      <div class="tab-pane" id="honors">
        <div class="container w-100 pt-3">
          <award-item
            v-for="(item,index) in awards"
            :aw-item="item"
            :key="index"
            :is-last="index===awards.length-1"></award-item>
          <small v-if="!awards" class="text-muted" >Content not available</small>
        </div>
      </div>
    </div>
  </main-panel>
</template>

<script>
import AwardItem from '@/components/items/AwardItem'
import MainPanel from '@/components/layout/MainPanel'
import SiteConfig from '@/site-conf'
import {StoreMx} from '@/mixins/StoreMx'
import StripedTable from '@/components/elements/StripedTable'

export default {
  name: 'SkillsView',
  mixins: [StoreMx],
  components: {StripedTable, MainPanel, AwardItem},
  created: function () {
    let vm = this
    this.skills = vm.storeGetItem('SKILLS')
    this.languages = vm.storeGetItem('LANGUAGES')
    this.awards = vm.storeGetItem('AWARDS')
  },
  data: function () {
    return {
      tabItems: SiteConfig.tabs.skillsView,
      skills: null,
      languages: null,
      awards: null
    }
  }
}
</script>

<style scoped>

</style>



