<template>
  <div class="card view-card">
    <div class="card-header">
      <bubble-tab :bub-items="tabItems" @bubClick="resetTab"></bubble-tab>
    </div>
    <div class="card-body" ref="cardBody">
      <slot></slot>
    </div>
  </div>
</template>

<script>
import BubbleTab from '@/components/elements/BubbleTab'
export default {
  name: 'MainPanel',
  components: {BubbleTab},
  props: ['tabItems'],
  methods: {
    resetTab: function () {
      this.$refs.cardBody.scrollTo(0, 0)
    }
  }
}
</script>

<style scoped>

  .view-card{
    border-radius: 0.5rem 0.5rem 0.5rem 0.5rem !important;
    box-shadow: 0px 2px 45px 5px rgba(0, 0, 0, 0.09);
    height: calc(100% - 1rem);
  }

  @media (min-width: 768px) {
    .view-card {
      height: 40.71rem;
    }

  }

  .view-card .card-header {
    border-radius: 0.5rem 0.5rem 0.0rem 0.0rem !important;
  }

  .view-card .card-body {
    overflow-y: auto;
  }
</style>



