<template>
  <main-panel :tab-items="tabItems">
    <div class="tab-content">
      <!-- Education Tab -->
      <div class="tab-pane active in" id="edu">
        <div class="container w-100 pt-2">
          <education-item
            v-for="(item,index) in education"
            :edu-item="item"
            :key="index"
            :is-last="index===education.length-1">
          </education-item>
          <small v-if="!education" class="text-muted" >Content not available</small>
        </div>
      </div>
      <!-- Experiences Tab -->
      <div class="tab-pane" id="exp">
        <div class="container w-100 pt-2">
          <experience-item
            v-for="(item,index) in experiences"
            :exp-item="item"
            :key="index"
            :is-last="index===experiences.length-1">
          </experience-item>
          <small v-if="!experiences" class="text-muted" >Content not available</small>
        </div>
      </div>
    </div>
  </main-panel>
</template>

<script>
import EducationItem from '@/components/items/EducationItem'
import ExperienceItem from '@/components/items/ExperienceItem'
import MainPanel from '@/components/layout/MainPanel'
import SiteConfig from '@/site-conf'
import {StoreMx} from '@/mixins/StoreMx'

export default {
  name: 'EducationView',
  mixins: [StoreMx],
  components: {MainPanel, ExperienceItem, EducationItem},
  created: function () {
    let vm = this
    this.education = vm.storeGetItem('EDUCATION')
    this.experiences = vm.storeGetItem('EXPERIENCES')
  },
  data: function () {
    return {
      tabItems: SiteConfig.tabs.educationView,
      education: null,
      experiences: null
    }
  }
}
</script>

<style scoped>

</style>



