<template>
  <div>
    <div class="row">
      <!--Info section -->
      <div class="col-12">

        <!-- Introductory line -->
        <h5 v-if="preItem.title">{{preItem.title}}</h5>
        <h5 v-else class="text-muted font-italic">Not defined</h5>

        <!-- Details -->
        <div class="pl-2 pt-2">
          <key-value key-text="Associated with" :value-text="preItem.association"></key-value>
          <key-value key-text="Course" :value-text="preItem.course"></key-value>
          <key-value key-text="Adviser" :value-text="preItem.adviser"></key-value>
          <key-value v-if="preItem.visiting" key-text="Visiting Professor" :value-text="preItem.visiting"></key-value>
          <key-value key-text="Date" :value-text="preItem.date"></key-value>

        </div>

        <!-- Buttons -->
        <div class="btn-group-sm pl-1 pt-1" v-if="preItem.extra">
          <button  v-if="preItem.extra.abstract" class="btn btn-outline-dark"
                   @click="$emit('absClick',preIndex)">
            <em class="fa fa-stream btn-icon"></em>Abstract
          </button>
          <a class="btn btn-outline-dark"
             v-if="preItem.extra.preUrl"
             :href="preItem.extra.preUrl"
             target="_blank">
            <em class="fa fa-globe btn-icon"></em>Presentation page
          </a>
          <button v-if="preItem.extra.gallery" class="btn btn-outline-dark"
                  @click="$emit('galClick',preIndex)">
            <em class="fa fa-images btn-icon"></em>Gallery
          </button>
        </div>

      </div>
    </div>

    <!-- Separator -->
    <hr v-show="!isLast" class="mt-4 mb-4">
  </div>
</template>

<script>
import KeyValue from '@/components/elements/KeyValue'
export default {
  name: 'PresentationItem',
  components: {KeyValue},
  props: ['preItem', 'preIndex', 'isLast']
}
</script>

<style scoped>
  em.btn-icon {
    margin-right: 0.25rem !important;
    line-height: 1rem;
  }
</style>



