<template>
  <!-- Modal -->
  <transition name="modal">
    <!-- Modal dark background-->
    <div class="modal-backdrop" v-if="modalShow" @click.self="closeModal()">

      <!-- Modal dialog-->
      <div class="modal-dialog modal-dialog-centered modal-lg" role="document">
        <div class="modal-content">

          <!-- Modal header-->
          <div class="modal-header bg-light">
            <h5 class="modal-title">{{modalTitle}}</h5>
            <button type="button" class="close"  aria-label="Close" @click="closeModal()">
              <span  style="line-height:1rem;">&times;</span>
            </button>
          </div>

          <!-- Modal body-->
          <div class="modal-body p-3" ref="modalBody">
            <p class="modal-par p-2">
              {{modalContent}}
            </p>
          </div>

          <!-- Modal footer-->
          <div class="modal-footer">
            <button type="button" class="btn btn-sm btn-outline-dark" @click="closeModal()">Close</button>
          </div>

        </div>
      </div>
    </div>
  </transition>

</template>

<script>
export default {
  name: 'DialogModal',
  props: ['modalShow', 'modalTitle', 'modalContent'],
  methods: {
    closeModal: function () {
      this.$emit('closemodal')
    }
  },
  mounted () {
    document.addEventListener('keydown', (e) => {
      if (this.modalShow === true && e.keyCode === 27) {
        this.closeModal()
      }
    })
  },
  updated () {
    /* this.$refs.modalBody.scrollTo(0, 0) */
  }
}
</script>

<style scoped>

  .modal-backdrop {
    position: fixed;
    top: 0;
    bottom: 0;
    left: 0;
    right: 0;
    background-color: var(--modal-dark-color);
    display: flex;
    justify-content: center;
    align-items: center;

    transition: all var(--modal-transition) ease;
    -o-transition: all var(--modal-transition) ease;
    -moz-transition: all var(--modal-transition) ease;
    -webkit-transition: all var(--modal-transition) ease;
  }

  .modal-content {
    transition: all var(--modal-transition) ease;
    -o-transition: all var(--modal-transition) ease;
    -moz-transition: all var(--modal-transition) ease;
    -webkit-transition: all var(--modal-transition) ease;

    max-width: 100vw;
  }

  .modal-body {
    overflow-y: scroll;
    max-height: 50vh;
  }

  .modal-par{
    text-align: justify;
    font-size: 1.1rem
  }

  .modal-enter {
    opacity: 0;

  }

  .modal-leave-active {
    opacity: 0;
  }

  .modal-enter .modal-content,
  .modal-leave-active .modal-content {
    transform: scale(1.1);
    -o-transform: scale(1.1);
    -moz-transform:scale(1.1);
    -ms-transform: scale(1.1);
    -webkit-transform: scale(1.1);
  }
</style>



