<template>
  <div id="app">

    <!-- Dialog modal -->
    <dialog-modal v-if="!modal.isGallery"
                  class="modal-depth"
                  :modal-title="modal.title"
                  :modal-content="modal.content"
                  :modal-show="modal.show"
                  @closemodal="modal.show=false"></dialog-modal>

    <!-- Gallery modal -->
    <gallery-modal v-if="modal.isGallery"
                   class="modal-depth"
                   :modal-title="modal.title"
                   :modal-content="modal.content"
                   :modal-show="modal.show"
                   @closemodal="modal.show=false"></gallery-modal>

    <!-- Mobile navigation bar -->
    <nav-bar v-if="!isLoading"></nav-bar>

    <!-- Main container -->
    <div class="main-container">

      <!-- Loading section -->
      <div v-if="isLoading" class="container align-self-center">
        <div class="row justify-content-center">
          <link :href="loadingImg"   rel="preload" as="image"/>
          <loading-div :loading-img="loadingImg"></loading-div>
        </div>
      </div>

      <!-- Main section -->
      <div v-else class="container align-self-md-center pt-md-0 extra-pt">
        <div class="row justify-content-center h-100">

          <!-- Sidebar -->
          <div class="col-3 d-none d-md-block pl-0 pr-0">
            <side-bar></side-bar>
          </div>

          <!-- Main panel -->
          <div class="col h-100 pr-3 mr-0 pr-m-0">
            <transition name="page" mode="out-in">
              <keep-alive>
                <router-view @show-modal="showModal"></router-view>
              </keep-alive>
            </transition>
          </div>

        </div>
      </div>

    </div>

  </div>
</template>

<script>

import SideBar from '@/components/layout/SideBar'
import NavBar from '@/components/layout/NavBar'
import DialogModal from '@/components/elements/DialogModal'
import GalleryModal from '@/components/elements/GalleryModal'
import {StoreMx} from '@/mixins/StoreMx'
import SiteConfig from '@/site-conf'
import LoadingDiv from '@/components/elements/LoadingDiv'

export default {
  name: 'app',
  mixins: [StoreMx],
  components: {
    LoadingDiv,
    NavBar,
    GalleryModal,
    DialogModal,
    SideBar
  },
  methods: {
    showModal (title, content, isGallery) {
      this.modal.show = true
      this.modal.title = title
      this.modal.content = content
      this.modal.isGallery = isGallery
    }

  },
  data: function () {
    return {
      modal: {title: '', content: '', show: false, isGallery: false},
      menuItems: SiteConfig.menuItems,
      footlinks: SiteConfig.footerLinks,
      isLoading: true,
      loadingImg: SiteConfig.sideBar.profileImg
    }
  },
  mounted () {
    let vm = this
    const pArray = []
    // Retrieve the necessary resources
    SiteConfig.res.forEach(res => {
      pArray.push(vm.storeFetchItem(res.url, res.name))
    })

    // Wait for the promises to finish
    Promise.all(pArray).then(function () {
      setTimeout(function () {
        vm.isLoading = false
      }, 1000)
    })
  }
}
</script>

<style lang="scss">
  @import './styles/custom-bootstrap.scss';
  @import '../node_modules/bootstrap/scss/bootstrap.scss';
</style>

<style>

  :root {
    --bubble-font-size:1rem;
    --bubble-radius:2.2rem;
    --bubble-dark-color:#292b2c;
    --bubble-light-color:white;
    --bubble-darker-color:black;
    --bubble-transition:0.3s;

    --modal-dark-color:rgba(0, 0, 0, 0.8);
    --modal-transition :0.3s;

    --footer-font-size:1rem;
    --footer-radius:2rem;
    --footer-dark-color: #292b2c;
    --footer-light-color: whitesmoke;
    --footer-back-color: white;
    --footer-transition: 0.2s;

    --menu-items-font-size: 1rem;
    --menu-items-title-font-size: 0.9rem;
    --menu-items-border-color: transparent;
    --menu-items-border-color-hover: #333333;
    --menu-items-separator-color: whitesmoke;
    --menu-items-text-color: #333333;
    --menu-items-text-color-hover: black;
    --menu-items-transition:0.2s;

    --menu-items-ex-separator-color: #292b2c;
    --menu-items-ex-font-size: 1.2rem;
    --menu-items-ex-title-font-size: 1.1rem;

    --thumb-size:6rem;
    --thumb-size-mob:4rem;

    --loading-img-size:7.2rem;
  }

  .main-container {
    position: fixed;
    display: flex;
    top: 0;
    bottom: 0;
    width: 100%;
  }

  .extra-pt {
    padding-top: 6rem;
  }

  .modal-depth{
    z-index: 5500;
  }
  .fade-enter-active, .fade-leave-active {
    transition: opacity 0.4s ease-in-out, transform 0.4s ease-in-out;
  }

  .fade-leave-to {
    opacity: 0;
    transform: translateY(-30%);
  }

  .fade-enter {
    opacity: 0;
    transform: translateY(-30%);
  }

  .page-enter-active, .page-leave-active {
    transition: opacity 0.4s ease-in-out, transform 0.4s ease-in-out;
  }

  .page-leave-to {
    opacity: 0;
    transform: translateX(-30%);
  }

  .page-enter {
    opacity: 0;
    transform: translateX(-30%);
  }

  html {
    font-size: 1rem;
  }

  /* Tiny devices (landscape phones, 0px and up) */
  @media (min-width: 0px) {
    html {
      font-size: 0.5rem;
    }

  }

  /* Extra Small devices (landscape phones, 300px and up) */
  @media (min-width: 300px) {
    html {
      font-size: 0.8rem;
    }
  }

  /* Small devices (landscape phones, 544px and up) */
  @media (min-width: 544px) {
    html {
      font-size: 0.8rem;
    }
  }

  /* Medium devices (tablets, 768px and up) The navbar toggle appears at this breakpoint */
  @media (min-width: 768px) {
    html {
      font-size: 0.64rem;
    }
  }

  /* Large devices (desktops, 992px and up) */
  @media (min-width: 992px) {
    html {
      font-size: 0.82rem;
    }

  }

  /* Extra large devices (large desktops, 1200px and up) */
  @media (min-width: 1200px) {
    html {
      font-size: 1rem;
    }
  }

  ::-webkit-scrollbar {
    width: 0.35rem;

  }

  /* Track */
  ::-webkit-scrollbar-track {
    background: white;
  }

  /* Handle */
  ::-webkit-scrollbar-thumb {
    background: #292b2caa;
    border-radius: 5px 5px 5px 5px;
    margin-right: 13px;
  }

  /* Handle on hover */
  ::-webkit-scrollbar-thumb:hover {
    background: black;
  }

  @font-face {
    font-family: "Effra";
    src: url("../static/webfonts/effra-regular.woff2") format("woff2");
  }
  @font-face {
    font-family: "Effra";
    src: url("../static/webfonts/effra-solid.woff2") format("woff2");
    font-weight: bold;
  }
  @font-face {
    font-family: "Effra";
    src: url("../static/webfonts/effra-regular-italic.woff2") format("woff2");
    font-style: italic;
  }
  @font-face {
    font-family: "Effra";
    src: url("../static/webfonts/effra-solid-italic.woff2") format("woff2");
    font-weight: bold;
    font-style: italic;

  }

</style>



