<template>
  <div>
    <div class="row">
      <!--Info section -->
      <div class="col-12">

        <!-- Introductory line -->
        <h5 v-if="prjItem.title">{{prjItem.title}}</h5>
        <h5 v-else class="text-muted font-italic">Not defined</h5>

        <!-- Details -->
        <div class="pl-2 pt-2">
          <key-value key-text="Associated with" :value-text="prjItem.association"></key-value>
          <key-value key-text="Course" :value-text="prjItem.course"></key-value>
          <key-value key-text="Adviser" :value-text="prjItem.adviser"></key-value>
          <key-value key-text="Date" :value-text="prjItem.date"></key-value>
        </div>

        <!-- Buttons -->
        <div class="btn-group-sm pl-1 pt-1" v-if="prjItem.extra">
          <button v-if="prjItem.extra.abstract" class="btn btn-outline-dark"
                  @click="$emit('absClick',prjIndex)">
            <em class="fa fa-stream btn-icon"></em>Abstract
          </button>
          <a class="btn btn-outline-dark"
             v-if="prjItem.extra.prjUrl"
             :href="prjItem.extra.prjUrl"
             target="_blank">
            <em class="fa fa-globe btn-icon"></em>Project page
          </a>
          <a class="btn btn-outline-dark"
             v-if="prjItem.extra.gitUrl"
             :href="prjItem.extra.gitUrl"
             target="_blank">
            <em class="fab fa-github btn-icon"></em>Github
          </a>
          <button v-if="prjItem.extra.gallery" class="btn btn-outline-dark"
                  @click="$emit('galClick',prjIndex)">
            <em class="fa fa-images btn-icon"></em>Gallery
          </button>
        </div>
      </div>
    </div>

    <!-- Separator -->
    <hr v-show="!isLast" class="mt-4 mb-4">
  </div>
</template>

<script>
import KeyValue from '@/components/elements/KeyValue'
export default {
  name: 'ProjectItem',
  components: {KeyValue},
  props: ['prjItem', 'prjIndex', 'isLast']
}
</script>

<style scoped>
  em.btn-icon {
    margin-right: 0.25rem !important;
    line-height: 1rem;
  }
</style>



