<template>
  <nav class="navbar navbar-depth navbar-dark bg-dark shadow rounded-bottom  d-block d-md-none">
    <div class="container-fluid">
      <!-- Navbar brand -->
      <span class="navbar-brand navbar-header">
        <img class="navbar-img rounded-circle shadow mr-2 d-inline-block align-top"
             :src="sideBar.profileImg"/>
        {{sideBar.displayName}}
      </span>

      <!-- Navbar toggle button -->
      <button class="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarNav"
              aria-controls="navbarNav" aria-expanded="false" aria-label="Toggle navigation">
        <span class="navbar-toggler-icon"></span>
      </button>

      <!-- Navbar collapsible region -->
      <div class="navbar-collapse collapse" id="navbarNav">

        <!-- Navbar menu items-->
        <menu-items-ex :menu-items="menuItems"></menu-items-ex>

        <!-- Navbar footer links-->
        <div class="row justify-content-center">
          <footer-links :foot-links="footLinks"></footer-links>
        </div>

      </div>
    </div>
  </nav>

</template>

<script>

import SiteConfig from '@/site-conf'
import FooterLinks from '@/components/elements/FooterLinks'
import MenuItemsEx from '@/components/elements/MenuItemsEx'

export default {
  name: 'NavBar',
  components: {MenuItemsEx, FooterLinks},
  data: function () {
    return {
      sideBar: SiteConfig.sideBar,
      menuItems: SiteConfig.menuItems,
      footLinks: SiteConfig.footerLinks
    }
  }
}
</script>

<style scoped>
  .navbar-depth {
    z-index: 5000;
  }

  .navbar-header {
    line-height: 3.2rem;
    font-size: 1.5rem
  }
  .navbar-img {
    width: 3rem;
    height: 3rem
  }
</style>



