<template>
  <div>
    <div class="row">
      <!--Info section -->
      <div class="col-12">

        <!-- Introductory line -->
        <h5 v-if="awItem.title">{{awItem.title}}</h5>
        <h5 v-else class="text-muted font-italic">Not defined</h5>

        <!-- Details -->
        <div class="pl-2 pt-2">
          <key-value key-text="Organization" :value-text="awItem.organization"></key-value>
          <key-value key-text="Location" :value-text="awItem.location"></key-value>
          <key-value key-text="Date" :value-text="awItem.date"></key-value>
        </div>

      </div>
    </div>

    <!-- Separator -->
    <hr v-show="!isLast" class="mt-4 mb-4">
  </div>
</template>

<script>
import KeyValue from '@/components/elements/KeyValue'
export default {
  name: 'AwardItem',
  components: {KeyValue},
  props: ['awItem', 'isLast']
}
</script>

<style scoped>

</style>



