<template>
  <main-panel :tab-items="tabItems">
    <div class="tab-content">
      <!-- Publications Tab -->
      <div class="tab-pane active in" id="pub">
        <div class="container w-100 pt-2">
          <publication-item
            v-for="(item,index) in publications"
            :pub-item="item"
            :key="index"
            :is-last="index===publications.length-1"
            :pub-index="index"
            @absClick="showAbstract">
          </publication-item>
          <small v-if="!publications" class="text-muted" >Content not available</small>
        </div>
      </div>
    </div>
  </main-panel>
</template>

<script>
import PublicationItem from '@/components/items/PublicationItem'
import MainPanel from '@/components/layout/MainPanel'
import SiteConfig from '@/site-conf'
import {StoreMx} from '@/mixins/StoreMx'

export default {
  name: 'Publication',
  mixins: [StoreMx],
  components: {MainPanel, PublicationItem},
  created: function () {
    let vm = this
    this.publications = vm.storeGetItem('PUBLICATIONS')
  },

  data: function () {
    return {
      tabItems: SiteConfig.tabs.publicationView,
      publications: null
    }
  },
  methods:
    {
      showAbstract: function (index) {
        this.$emit('show-modal',
          this.publications[index].title,
          this.publications[index].extra.abstract)
      }
    }
}
</script>

<style scoped>

</style>



